code.setup:
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
gsap.registerPlugin(ScrollTrigger);

code.fade_up:
// Revelar elementos ao entrar na viewport
gsap.utils.toArray('[data-reveal]').forEach((el) => {
  gsap.from(el, {
    opacity: 0,
    y: 50,
    duration: 0.9,
    ease: 'power3.out',
    scrollTrigger: {
      trigger: el,
      start: 'top 85%',
      toggleActions: 'play none none none',
    }
  });
});

code.clip_reveal:
// Clip-path reveal — elegante para headlines e imagens
gsap.utils.toArray('.headline-reveal').forEach((el) => {
  gsap.from(el, {
    clipPath: 'inset(0 100% 0 0)',
    opacity: 0,
    duration: 1.1,
    ease: 'power4.inOut',
    scrollTrigger: {
      trigger: el,
      start: 'top 80%',
    }
  });
});

code.scrub_parallax:
// Parallax de background ao scroll
const bg = document.querySelector('.hero-bg');
gsap.to(bg, {
  yPercent: -30,
  ease: 'none',
  scrollTrigger: {
    trigger: '.hero',
    start: 'top top',
    end: 'bottom top',
    scrub: true,  // scrub: true ou número (suavidade)
  }
});

code.pin_section:
// Seção pinada com animação interna
const tl = gsap.timeline({
  scrollTrigger: {
    trigger: '.pin-section',
    pin: true,
    start: 'top top',
    end: '+=200%',
    scrub: 1,
  }
});
tl.to('.pin-text', { opacity: 0, y: -50 })
  .to('.pin-image', { scale: 1.2 }, '<')
  .to('.pin-cta', { opacity: 1, y: 0 });
